from dataclasses import dataclass
from datetime import datetime, UTC
import httpx

@dataclass
class StalenessResult:
    stale: bool
    reason: str = ""
    refreshed_value: dict | None = None   # filled in if refresh succeeded

async def check_record_staleness(
    record_id: str,
    snapshot_etag: str,        # ETag or version stored at checkpoint time
) -> StalenessResult:
    async with httpx.AsyncClient() as client:
        resp = await client.get(f"https://api.example.com/records/{record_id}")
        if resp.status_code == 404:
            return StalenessResult(stale=True, reason="Record deleted since checkpoint")
        current = resp.json()
        current_etag = current.get("etag") or current.get("version")
        if current_etag != snapshot_etag:
            return StalenessResult(
                stale=True,
                reason=f"Record modified (was {snapshot_etag}, now {current_etag})",
                refreshed_value=current,
            )
    return StalenessResult(stale=False)

async def check_token_validity(token: str) -> StalenessResult:
    async with httpx.AsyncClient() as client:
        resp = await client.get(
            "https://api.example.com/auth/introspect",
            headers={"Authorization": f"Bearer {token}"},
        )
        if resp.status_code != 200 or not resp.json().get("active"):
            return StalenessResult(stale=True, reason="Auth token expired")
    return StalenessResult(stale=False)

from enum import StrEnum

class ResumeStrategy(StrEnum):
    DIRECT   = "direct"
    REFRESH  = "refresh"
    RESTART  = "restart"
    ABORT    = "abort"

@dataclass
class ResumeDecision:
    strategy: ResumeStrategy
    reason: str
    refreshed_context: dict | None = None   # available when strategy == REFRESH

async def decide_resume_strategy(snapshot: "AgentSnapshot") -> ResumeDecision:
    checks: list[StalenessResult] = []

    # Check each resource recorded in the snapshot's metadata
    for resource in snapshot.metadata.get("watched_resources", []):
        result = await check_record_staleness(
            resource["id"], resource["etag"]
        )
        checks.append(result)

    # Check auth token if present
    token = snapshot.metadata.get("auth_token")
    if token:
        checks.append(await check_token_validity(token))

    stale = [c for c in checks if c.stale]
    if not stale:
        return ResumeDecision(strategy=ResumeStrategy.DIRECT, reason="All resources current")

    # Some are stale — can we refresh them all?
    refreshable = [c for c in stale if c.refreshed_value is not None]
    if len(refreshable) == len(stale):
        merged = {f"resource_{i}": c.refreshed_value for i, c in enumerate(refreshable)}
        return ResumeDecision(
            strategy=ResumeStrategy.REFRESH,
            reason=f"{len(stale)} resource(s) refreshed",
            refreshed_context=merged,
        )

    # Some stale and unrefreshable — is the task restartable?
    if snapshot.metadata.get("restartable", False):
        return ResumeDecision(
            strategy=ResumeStrategy.RESTART,
            reason=f"{len(stale)} resource(s) unrefreshable; restarting",
        )

    return ResumeDecision(
        strategy=ResumeStrategy.ABORT,
        reason=f"Cannot continue: {'; '.join(c.reason for c in stale)}",
    )

class ResourceTracker:
    def __init__(self):
        self._resources: list[dict] = []

    def track(self, resource_id: str, etag: str, resource_type: str = "record"):
        self._resources.append({
            "id": resource_id,
            "etag": etag,
            "type": resource_type,
        })

    def as_metadata(self) -> dict:
        return {"watched_resources": self._resources}

# In the agent loop, pass a tracker alongside the snapshot:
tracker = ResourceTracker()

async def _execute_tool_with_tracking(
    name: str, params: dict, tracker: ResourceTracker
) -> str:
    result_raw = await _execute_tool(name, params)
    result = json.loads(result_raw) if isinstance(result_raw, str) else result_raw
    # If the tool returns a versioned record, register it
    if isinstance(result, dict) and "id" in result and "etag" in result:
        tracker.track(result["id"], result["etag"])
    return result_raw if isinstance(result_raw, str) else json.dumps(result)
